'use strict';

// Simplified get-intrinsic for ts-aot
// The original uses eval-based %Name% syntax to look up builtins.
// We directly return the known intrinsics.
var INTRINSICS = {
    '%Array%': Array,
    '%Boolean%': Boolean,
    '%Date%': Date,
    '%Error%': Error,
    '%EvalError%': EvalError,
    '%Function%': Function,
    '%JSON%': JSON,
    '%Map%': typeof Map !== 'undefined' ? Map : undefined,
    '%Math%': Math,
    '%Number%': Number,
    '%Object%': Object,
    '%Promise%': typeof Promise !== 'undefined' ? Promise : undefined,
    '%Proxy%': typeof Proxy !== 'undefined' ? Proxy : undefined,
    '%RangeError%': RangeError,
    '%ReferenceError%': ReferenceError,
    '%Reflect%': typeof Reflect !== 'undefined' ? Reflect : undefined,
    '%RegExp%': RegExp,
    '%Set%': typeof Set !== 'undefined' ? Set : undefined,
    '%String%': String,
    '%Symbol%': typeof Symbol !== 'undefined' ? Symbol : undefined,
    '%SyntaxError%': SyntaxError,
    '%TypeError%': TypeError,
    '%URIError%': URIError,
    '%WeakMap%': typeof WeakMap !== 'undefined' ? WeakMap : undefined,
    '%WeakSet%': typeof WeakSet !== 'undefined' ? WeakSet : undefined,
};

module.exports = function GetIntrinsic(name, allowMissing) {
    if (typeof name !== 'string' || name.length === 0) {
        throw new TypeError('intrinsic name must be a non-empty string');
    }

    // Direct lookup
    var val = INTRINSICS[name];
    if (typeof val !== 'undefined') {
        return val;
    }

    // Handle dotted paths like '%Array.prototype.push%'
    var parts = name.replace(/^%|%$/g, '').split('.');
    var base = INTRINSICS['%' + parts[0] + '%'];
    if (!base) {
        if (allowMissing) return undefined;
        throw new TypeError('intrinsic ' + name + ' does not exist');
    }
    for (var i = 1; i < parts.length; i++) {
        base = base[parts[i]];
        if (base === null || base === undefined) {
            if (allowMissing) return undefined;
            throw new TypeError('intrinsic ' + name + ' does not exist');
        }
    }
    return base;
};
